import React from 'react';
import PropTypes from 'prop-types';
import { ButtonGroup, ToggleButton } from '@mui/material';
import { colors } from "../../utils/designTokens";

const FAWButtonGroupTabs = ({ 
  options = [], 
  selected,
  onChange,
  size = 'medium',
  disabled = false,
  orientation = 'horizontal',
  sx = {},
  ...props
}) => {
  const handleChange = (event, newValue) => {
    if (newValue !== null && onChange) {
      onChange(newValue);
    }
  };


  return (
    <ButtonGroup
      orientation={orientation}
      disabled={disabled}
      sx={{
        width: '100% !important',
        display: 'flex !important',
        gap: '0 !important',
        borderRadius: '0 !important',
        padding: '0 !important',
        boxShadow: 'none !important',
        justifyContent: 'stretch !important',
          '& .MuiToggleButton-root': {
          flex: '1 !important', // Make buttons take equal width
          border: `1px solid ${colors.ui.border.static} !important`,
          borderRadius: '0 !important',
          '&:first-of-type': {
            borderTopLeftRadius: '8px !important',
            borderBottomLeftRadius: '8px !important',
          },
          '&:last-of-type': {
            borderTopRightRadius: '8px !important',
            borderBottomRightRadius: '8px !important',
          },
          '&:not(:first-of-type)': {
            borderLeft: 'none !important',
          },
          '&.Mui-selected': {
            backgroundColor: `${colors.type.default} !important`, // Dark/black background
            color: `${colors.type.inverse} !important`,
            '&:hover': {
              backgroundColor: `${colors.action.primary.active} !important`,
            },
          },
          '&:hover': {
            backgroundColor: `${colors.background.secondary} !important`,
          },
        },
        ...sx,
      }}
      {...props}
    >
      {options.map((option, index) => (
        <ToggleButton
          key={`${option.value}_${index}`}
          value={option.value}
          selected={selected === option.value}
          onChange={handleChange}
          disabled={disabled}
          sx={{
            textTransform: 'none',
            ...option.sx,
          }}
        >
          {option.label}
        </ToggleButton>
      ))}
    </ButtonGroup>
  );
};

FAWButtonGroupTabs.propTypes = {
  options: PropTypes.arrayOf(PropTypes.shape({
    value: PropTypes.any.isRequired,
    label: PropTypes.node.isRequired,
    sx: PropTypes.object,
  })),
  selected: PropTypes.any,
  onChange: PropTypes.func,
  size: PropTypes.oneOf(['small', 'medium']),
  disabled: PropTypes.bool,
  orientation: PropTypes.oneOf(['horizontal', 'vertical']),
  sx: PropTypes.object,
};

export default FAWButtonGroupTabs;
